<style lang="scss">
  .footer {
    @include fontSize(20px);
    padding: 50px 0;
    background: #000000;
    text-align: center;
    color: #ffffff;

    > .wrapper {
      display: grid;
      gap: 50px;
      justify-items: center;
    }

    &__powered {
      display: grid;
      grid-template-columns: max-content max-content;
      gap: 5px;
      align-items: center;
      transition: color .2s;

      > svg > path {
        transition: fill .2s;
      }

      &:hover, &:focus {
        color: $accent;

        > svg > path {
          fill: $accent;
        }
      }
    }
  }

  // Responsiveness

  @media (max-width: 400px) {
    .footer__powered {
      grid-template-columns: 1fr;
      gap: 10px;
    }
  }
</style>
